# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI

struct PromoData: Equatable {
    let code: String
    let discount: Int
}

final class UserAccount: ObservableObject {
    @Published var appliedPromo: PromoData?
    @Published var statusMessage: String = "No promo applied"

    func applyPromo(code: String, discount: Int) {
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        let clampedDiscount = max(0, min(discount, 100))
        let promo = PromoData(code: sanitizedCode, discount: clampedDiscount)
        appliedPromo = promo
        statusMessage = "Applied promo \(promo.code) for \(promo.discount)% off"
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    private init() {}

    func parsePromo(from url: URL) -> PromoData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return nil
        }

        guard let host = components.host?.lowercased(), host == "myapp.com" else {
            return nil
        }

        let path = components.path.lowercased()
        guard path == "/promo" || path == "promo" else {
            return nil
        }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value ?? ""

        guard !code.isEmpty, let discount = Int(discountString) else {
            return nil
        }

        return PromoData(code: code, discount: max(0, min(discount, 100)))
    }

    @discardableResult
    func handle(url: URL, for account: UserAccount) -> Bool {
        guard let promo = parsePromo(from: url) else {
            return false
        }
        account.applyPromo(code: promo.code, discount: promo.discount)
        return true
    }
}

final class AppState: ObservableObject {
    @Published var userAccount = UserAccount()

    func handleIncomingURL(_ url: URL) {
        let handled = PromoLinkHandler.shared.handle(url: url, for: userAccount)
        if !handled {
            userAccount.statusMessage = "Invalid or unsupported promo link"
        }
    }
}

